            const doc = parser.parseFromString(html, 'text/html');

            return this.extractContactInfo(doc);
        } catch (error) {
            console.error('Error scraping contact info:', error);
            throw new Error(`Failed to scrape contact information: ${error.message}`);
        }
    }

