     * @param {Document} doc - Parsed HTML document
     * @returns {Object} Extracted contact information
     */
    extractContactInfo(doc) {
        const contactInfo = {
            emails: [],
            phones: [],
            address: null,
            companyName: null,
            website: null,
            socialMedia: {}
