            if (empty($confirmationNumber)) {
                throw new InvalidArgumentException('Confirmation number is required');
            }

            $endpoint = '/bookings/' . urlencode($confirmationNumber) . '/cancel';
            $response = $this->makeApiRequest('POST', $endpoint);

            if (!$response['success']) {
